### 2. `game.py`

```python
from board import Board, Piece

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def print_board(self):
        self.board.print_board()

    def switch_player(self):
        self.current_player = 'b' if self.current_player == 'r' else 'r'

    def is_valid_move(self, start, end):
        row_diff = abs(start[0] - end[0])
        col_diff = abs(start[1] - end[1])

        piece = self.board.board[start[0]][start[1]]
        if not piece:
            return False

        if piece.color != self.current_player:
            return False

        if row_diff == 1 and col_diff == 1 and self.board.board[end[0]][end[1]] is None:
            return True

        if row_diff == 2 and col_diff == 2:
            jump_piece = self.board.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2]
            if jump_piece and jump_piece.color != piece.color and self.board.board[end[0]][end[1]] is None:
                return True

        return False

    def make_move(self, start, end):
        row_diff = abs(start[0] - end[0])
        col_diff = abs(start[1] - end[1])

        piece = self.board.board[start[0]][start[1]]
        jump_piece = None
        if row_diff == 2 and col_diff == 2:
            jump_piece = self.board.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2]
            self.board.board[jump_piece.row][jump_piece.col] = None

        self.board.board[end[0]][end[1]] = piece
        self.board.board[start[0]][start[1]] = None

        if abs(end[0] - start[0]) == 2:
            jump_piece.king = True

        self.switch_player()

    def check_win(self):
        # Check for win condition (all pieces of one color are captured)
        for row in range(8):
            for col in range(8):
                piece = self.board.board[row][col]
                if piece and piece.color == 'r':
                    return False
        return True

    def run(self):
        while not self.check_win():
            self.print_board()
            move = input(f"Player {self.current_player}, enter your move (from-to): ").split('-')
            start = (int(move[0][1]), ord(move[0][0]) - 97)
            end = (int(move[1][1]), ord(move[1][0]) - 97)

            if self.is_valid_move(start, end):
                self.make_move(start, end)
            else:
                print("Invalid move. Try again.")

        self.print_board()
        print(f"Player {self.current_player} wins!")
```

